const raw = $input.first().json.output;
let parsed;
try {
  // Try to extract JSON from the output
  const match = raw.match(/\{[\s\S]*\}/);
  if (match) {
    parsed = JSON.parse(match[0]);
  } else {
    parsed = JSON.parse(raw);
  }
} catch(e) {
  return [{ json: { error: e.message, raw_output: raw } }];
}

return [{ json: parsed }];
